/** Array of all RHS color entries for iteration. */
export const RHS_COLOR_LIST: RHSColor[] = Object.values(RHS_COLORS);

/** Look up an RHS colour by its code. Returns undefined if not found. */
export function getRHSColor(rhs: string): RHSColor | undefined {
  return RHS_COLORS[rhs];
}
